<template>
  <div class="question slightly-shadowed">
    <h3>{{ question.text }}</h3>
    <div class="show-answer-wrapper">
      <div class="show-answer-toggle noselect" @click="showAnswer">
        {{ buttonText }}
      </div>
    </div>

    <!--    <p class="question-answer" :class="{hidden: isHidden}" >{{ question.questionAnswer }}</p>-->
    <div v-html="question.html" class="question-answer" v-if="!isHidden"></div>
  </div>
</template>

<script>
export default {
  name: "Question",
  props: {
    question: Object
  },
  data() {
    return {
      isHidden: true
    };
  },
  methods: {
    showAnswer() {
      this.isHidden = !this.isHidden;
    }
  },
  computed: {
    buttonText() {
      return this.isHidden ? "Show Answer" : "Hide Answer";
    }
  }
};
</script>

